/**
 * Интерфейс для работы с двумерными векторами.
 */
declare interface Vec2Lib {
    /**
     * Создает новый вектор с заданными координатами.
     * @param target - целевой вектор, который будет изменен.
     * @param a - координата x.
     * @param b - координата y.
     * @returns новый вектор.
     */
    readonly make: (target: vec2, a: number, b: number) => vec2;

    /**
     * Создает копию заданного вектора.
     * @param target - целевой вектор, который будет изменен.
     * @param v - вектор, который нужно скопировать.
     * @returns копия вектора.
     */
    readonly dup: (target: vec2, v: vec2) => vec2;

    /**
     * Получает вектор из неизвестного значения.
     * @param v - неизвестное значение.
     * @returns вектор или undefined, если значение не является вектором.
     */
    readonly get: (v: unknown) => vec2 | undefined;

    /**
     * Проверяет, равны ли два вектора.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns true, если векторы равны, иначе false.
     */
    readonly eq: (a: vec2, b: vec2) => boolean;

    /**
     * Складывает два вектора.
     * @param target - целевой вектор, который будет изменен.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns результат сложения.
     */
    readonly add: (target: vec2, a: vec2, b: vec2) => vec2;

    /**
     * Вычитает один вектор из другого.
     * @param target - целевой вектор, который будет изменен.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns результат вычитания.
     */
    readonly sub: (target: vec2, a: vec2, b: vec2) => vec2;

    /**
     * Умножает вектор на скаляр.
     * @param target - целевой вектор, который будет изменен.
     * @param a - вектор.
     * @param f - скаляр.
     * @returns результат умножения.
     */
    readonly mul: (target: vec2, a: vec2, f: number) => vec2;

    /**
     * Вычисляет длину вектора.
     * @param a - вектор.
     * @returns длина вектора.
     */
    readonly len: (a: vec2) => number;

    /**
     * Вычисляет квадрат длины вектора.
     * @param a - вектор.
     * @returns квадрат длины вектора.
     */
    readonly lensqr: (a: vec2) => number;

    /**
     * Вычисляет расстояние между двумя векторами.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns расстояние между векторами.
     */
    readonly distance: (a: vec2, b: vec2) => number;

    /**
     * Вычисляет квадрат расстояния между двумя векторами.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns квадрат расстояния между векторами.
     */
    readonly distancesqr: (a: vec2, b: vec2) => number;

    /**
     * Нормализует вектор.
     * @param target - целевой вектор, который будет изменен.
     * @param a - вектор.
     * @returns нормализованный вектор.
     */
    readonly normalize: (target: vec2, a?: vec2) => vec2;

    /**
     * Инвертирует вектор.
     * @param target - целевой вектор, который будет изменен.
     * @param a - вектор.
     * @returns инвертированный вектор.
     */
    readonly neg: (target: vec2, a?: vec2) => vec2;

    /**
     * Вычисляет угол вектора.
     * @param a - вектор.
     * @returns угол вектора.
     */
    readonly angle: (a: vec2) => number;

    /**
    * Вычисляет векторное произведение двух векторов.
    * @param a - первый вектор.
    * @param b - второй вектор.
    * @returns векторное произведение.
    */
    readonly cross: (a: vec2, b: vec2) => number;

    /**
     * Вычисляет скалярное произведение двух векторов.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns скалярное произведение.
     */
    readonly dot: (a: vec2, b: vec2) => number;

    /**
     * Вычисляет минимальный вектор из двух векторов.
     * @param target - целевой вектор, который будет изменен.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns минимальный вектор.
     */
    readonly min: (target: vec2, a: vec2, b: vec2) => vec2;

    /**
     * Вычисляет максимальный вектор из двух векторов.
     * @param target - целевой вектор, который будет изменен.
     * @param a - первый вектор.
     * @param b - второй вектор.
     * @returns максимальный вектор.
     */
    readonly max: (target: vec2, a: vec2, b: vec2) => vec2;

    /**
     * Поворачивает вектор на заданный угол.
     * @param target - целевой вектор, который будет изменен.
     * @param v - вектор.
     * @param sinx - синус угла.
     * @param cosx - косинус угла.
     * @returns повернутый вектор.
     */
    readonly rotate: (target: vec2, v: vec2, sinx: number, cosx: number) => vec2;
}

